#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        if(N % 4 != 0){
            printf("NO\n");
            continue;
        }
        printf("YES\n");
        int half = N/2;
        int k = N/4;
        // array A
        for(int i=1;i<=half;i++){
            int val = (i<=k) ? i : i+half;
            printf("%d", val);
            if(i<half) printf(" ");
        }
        printf("\n");
        // array B
        for(int i=1;i<=half;i++){
            int val = (i<=k) ? i+half : i;
            printf("%d", val);
            if(i<half) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

