    out.push('NO');
    continue;
  }
  out.push('YES');
  const half = N / 2;
  const k = N / 4;
  let A = [];
  let B = [];
  for (let i = 1; i <= half; i++) {
    if (i <= k) {
      A.push(i);
      B.push(i + half);
    } else {
      A.push(i + half);
      B.push(i);
    }
